div.p:
STORE-RELEASE (smp_store_release):
c
// Ensures all writes BEFORE this
// are visible BEFORE the store
io_uring_smp_store_release(p, v) {
asm volatile("" ::: "memory");
*p = v;
}

LOAD-ACQUIRE (smp_load_acquire):
c
// Ensures all reads AFTER this
// see data written BEFORE
// the load's matching release
io_uring_smp_load_acquire(p) {
typeof(*(p)) v = *p;
asm volatile("" ::: "memory");
return v;
}
